import { DependencyList } from 'react';
import { EmitterListeners, MediaEvents } from '../types';
export type EventEmittersName = keyof MediaEvents;
export type Handler<T extends EventEmittersName> = (eventArgs: MediaEvents[T]) => void;
/** Media Listener hook that subscribes and unsubscribes from MediaStore's `emitter`
 * or, a useEffect that listens to `MediaStore` events
 * @category hooks
 * @category MediaStore
 */
export declare const useMediaListener: <T extends EventEmittersName>(eventName: T, handler: Handler<T>, target?: EmitterListeners, deps?: DependencyList) => void;
